import React, { useState, useEffect, useRef } from 'react';
import { Outlet, useNavigate, useLocation, NavLink } from 'react-router-dom';
import { useAuth } from '../../context/AuthContext';
import axios from 'axios';

const adminNav = [
  { section: 'Overview', items: [{ to: '/admin/dashboard', label: 'Dashboard' }] },
  { section: 'Management', items: [
    { to: '/admin/students', label: 'Students' },
    { to: '/admin/routes', label: 'Bus Routes' },
    { to: '/admin/fees', label: 'Fee Records' },
  ]},
  { section: 'Scheduling', items: [
    { to: '/admin/schedules', label: 'Schedules' },
    { to: '/admin/upcoming', label: 'Upcoming Dues' },
    { to: '/admin/overdue', label: 'Overdue' },
  ]},
];

const studentNav = [
  { section: 'Portal', items: [
    { to: '/student/dashboard', label: 'Dashboard' },
    { to: '/student/fees', label: 'Fees & Payments' },
    { to: '/student/schedule', label: 'Schedule' },
    { to: '/student/profile', label: 'Profile' },
  ]},
];

const pageTitles = {
  '/admin/dashboard': { title: 'Dashboard', sub: 'Overview and analytics' },
  '/admin/students': { title: 'Students', sub: 'Manage student records' },
  '/admin/routes': { title: 'Bus Routes', sub: 'Routes and fare structure' },
  '/admin/fees': { title: 'Fee Records', sub: 'Payment collection and tracking' },
  '/admin/schedules': { title: 'Schedules', sub: 'Due dates and late fee rules' },
  '/admin/upcoming': { title: 'Upcoming Dues', sub: 'Fees due within 30 days' },
  '/admin/overdue': { title: 'Overdue Fees', sub: 'Past-due payments' },
  '/student/dashboard': { title: 'Dashboard', sub: 'Account overview' },
  '/student/fees': { title: 'Fees & Payments', sub: 'Pay fees and view receipts' },
  '/student/schedule': { title: 'Schedule', sub: 'Due dates and payment policy' },
  '/student/profile': { title: 'Profile', sub: 'Account and route information' },
  '/student/notifications': { title: 'Notifications', sub: 'Alerts and reminders' },
};

export default function Layout() {
  const { user, logout, isAdmin } = useAuth();
  const navigate = useNavigate();
  const location = useLocation();
  const [sidebarOpen, setSidebarOpen] = useState(false);
  const [notifications, setNotifications] = useState([]);
  const [showNotif, setShowNotif] = useState(false);
  const notifRef = useRef(null);

  useEffect(() => {
    axios.get('/notifications').then(r => setNotifications(r.data)).catch(() => {});
  }, [location.pathname]);

  useEffect(() => {
    const handler = (e) => { if (notifRef.current && !notifRef.current.contains(e.target)) setShowNotif(false); };
    document.addEventListener('mousedown', handler);
    return () => document.removeEventListener('mousedown', handler);
  }, []);

  const unread = notifications.filter(n => !n.isRead).length;
  const page = pageTitles[location.pathname] || { title: 'Portal', sub: '' };
  const navGroups = isAdmin ? adminNav : studentNav;

  const handleLogout = () => { logout(); navigate('/login'); };

  const markAllRead = async () => {
    await axios.put('/notifications/read-all');
    setNotifications(n => n.map(x => ({ ...x, isRead: true })));
  };

  const timeAgo = (date) => {
    const diff = Date.now() - new Date(date);
    const m = Math.floor(diff / 60000);
    if (m < 1) return 'just now';
    if (m < 60) return `${m}m ago`;
    const h = Math.floor(m / 60);
    if (h < 24) return `${h}h ago`;
    return `${Math.floor(h / 24)}d ago`;
  };

  return (
    <div className="layout">
      {sidebarOpen && <div className="sidebar-overlay" onClick={() => setSidebarOpen(false)} />}
      <aside className={`sidebar ${sidebarOpen ? 'open' : ''}`}>
        <div className="sidebar-logo">
          <div className="brand-mark">CB</div>
          <div>
            <h1>Campus Bus</h1>
            <span>{isAdmin ? 'Administration' : 'Student Portal'}</span>
          </div>
        </div>
        <nav className="sidebar-nav">
          {navGroups.map(group => (
            <div key={group.section} className="nav-group">
              <div className="nav-section-label">{group.section}</div>
              {group.items.map(item => (
                <NavLink key={item.to} to={item.to} className={({ isActive }) => `nav-item ${isActive ? 'active' : ''}`} onClick={() => setSidebarOpen(false)}>
                  <span className="nav-dot" />
                  <span>{item.label}</span>
                </NavLink>
              ))}
            </div>
          ))}
        </nav>
        <div className="sidebar-footer">
          <div className="user-card">
            <div className="user-avatar">{user?.name?.charAt(0).toUpperCase()}</div>
            <div className="user-info">
              <div className="user-name">{user?.name}</div>
              <div className="user-role">{user?.role}</div>
            </div>
          </div>
          <button className="logout-btn" onClick={handleLogout}>Sign Out</button>
        </div>
      </aside>

      <main className="main-content">
        <header className="topbar">
          <div className="topbar-left">
            <button className="menu-toggle" onClick={() => setSidebarOpen(true)} aria-label="Open menu">☰</button>
            <div>
              <h2>{page.title}</h2>
              <p>{page.sub}</p>
            </div>
          </div>
          <div className="topbar-right">
            <div className="topbar-user">{user?.name}</div>
            <div style={{ position: 'relative' }} ref={notifRef}>
              <button className="notif-btn" onClick={() => setShowNotif(!showNotif)} title="Notifications" aria-label="Notifications">
                <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><path d="M18 8A6 6 0 0 0 6 8c0 7-3 9-3 9h18s-3-2-3-9"/><path d="M13.73 21a2 2 0 0 1-3.46 0"/></svg>
                {unread > 0 && <span className="notif-dot" />}
              </button>
              {showNotif && (
                <div className="notif-panel">
                  <div className="notif-header">
                    <span style={{ fontWeight: 700, fontSize: 14 }}>Notifications {unread > 0 && <span className="badge badge-overdue" style={{ marginLeft: 6 }}>{unread}</span>}</span>
                    {unread > 0 && <button className="btn btn-outline btn-sm" onClick={markAllRead}>Mark all read</button>}
                  </div>
                  <div className="notif-list">
                    {notifications.length === 0 ? (
                      <div className="notif-empty">No notifications</div>
                    ) : notifications.slice(0, 8).map(n => (
                      <div key={n.id} className={`notif-item ${!n.isRead ? 'unread' : ''}`} onClick={() => { axios.put(`/notifications/${n.id}/read`); setNotifications(prev => prev.map(x => x.id === n.id ? { ...x, isRead: true } : x)); }}>
                        <div className="notif-item-title">{n.title}</div>
                        <div className="notif-item-msg">{n.message}</div>
                        <div className="notif-item-time">{timeAgo(n.createdAt)}</div>
                      </div>
                    ))}
                  </div>
                  <div className="notif-footer">
                    {!isAdmin && unread > 0 && (
                      <button className="btn btn-outline btn-sm" onClick={() => { setShowNotif(false); navigate('/student/notifications'); }}>View all</button>
                    )}
                    <button className="btn btn-outline btn-sm" onClick={() => setShowNotif(false)}>Close</button>
                  </div>
                </div>
              )}
            </div>
            <div className="topbar-date">
              {new Date().toLocaleDateString('en-IN', { weekday: 'short', day: 'numeric', month: 'short', year: 'numeric' })}
            </div>
          </div>
        </header>
        <div className="page-content">
          <Outlet />
        </div>
      </main>
    </div>
  );
}
